var COURSE_ID_PL = [{day: 1, title: `Salam dan memperkenalkan diri`, title_native: `Powitania i przedstawianie się`, focus: `Hari pertama dimulai di Warszawa, saat Anda tiba dan perlu menyapa orang dengan sopan. Fokusnya adalah salam dasar, nama, dan kata-kata paling penting untuk memulai percakapan singkat.`, vocab: [{pl: `cześć`, id: `halo / hai`, ipa: `cheshch`},{pl: `dzień dobry`, id: `selamat pagi / siang`, ipa: `djen dob-ri`},{pl: `dobry wieczór`, id: `selamat malam`, ipa: `dob-ri vye-chur`},{pl: `do widzenia`, id: `sampai jumpa`, ipa: `do vi-dze-nya`},{pl: `proszę`, id: `silakan / tolong`, ipa: `pro-she`},{pl: `dziękuję`, id: `terima kasih`, ipa: `jen-koo-ye`},{pl: `tak`, id: `ya`, ipa: `tak`},{pl: `nie`, id: `tidak`, ipa: `nye`},{pl: `przepraszam`, id: `permisi / maaf`, ipa: `pshe-pra-sham`},{pl: `imię`, id: `nama depan`, ipa: `i-mye`}], phrases: [{pl: `Cześć, mam na imię Andi.`, id: `Hai, nama saya Andi.`, ipa: `cheshch, mam na i-mye an-di`},{pl: `Dzień dobry, jestem z Indonezji.`, id: `Selamat siang, saya dari Indonesia.`, ipa: `djen dob-ri, yes-tem z in-do-nez-yi`},{pl: `Jak masz na imię?`, id: `Siapa namamu?`, ipa: `yak mash na i-mye`},{pl: `Miło mi.`, id: `Senang bertemu denganmu.`, ipa: `mi-wo mi`},{pl: `Do widzenia!`, id: `Sampai jumpa!`, ipa: `do vi-dze-nya`},{pl: `Przepraszam, czy mówisz po angielsku?`, id: `Permisi, apakah Anda berbicara bahasa Inggris?`, ipa: `pshe-pra-sham, chi moo-vish po an-gyel-sku`}], grammar: `Dalam bahasa Polandia, kata kerja sering berubah sesuai orangnya. “Mam” berarti “saya punya”, jadi “Mam na imię...” secara harfiah berarti “Saya punya nama...”. Untuk situasi sopan dengan orang asing, gunakan “dzień dobry” daripada “cześć”.`, practice: [`Ucapkan “Dzień dobry” dan “Do widzenia” seolah-olah Anda masuk dan keluar dari toko kecil di Warszawa.`,`Perkenalkan diri Anda dengan pola “Mam na imię...”.`,`Tanyakan nama seseorang dengan “Jak masz na imię?”.`,`Jawab “Miło mi” setelah seseorang memperkenalkan diri.`,`Latih membedakan “tak” dan “nie” dalam jawaban cepat.`]},{day: 2, title: `Ungkapan penting untuk bertahan`, title_native: `Najważniejsze zwroty przetrwania`, focus: `Di Kraków, Anda mungkin belum mengerti semua kata, jadi Anda perlu frasa penyelamat. Hari ini melatih cara meminta bantuan, meminta pengulangan, dan mengatakan bahwa Anda tidak mengerti.`, vocab: [{pl: `pomoc`, id: `bantuan`, ipa: `po-mots`},{pl: `język`, id: `bahasa`, ipa: `yen-zik`},{pl: `polski`, id: `bahasa Polandia / Polandia`, ipa: `pol-ski`},{pl: `angielski`, id: `bahasa Inggris`, ipa: `an-gyel-ski`},{pl: `rozumiem`, id: `saya mengerti`, ipa: `ro-zu-myem`},{pl: `wiem`, id: `saya tahu`, ipa: `vyem`},{pl: `powoli`, id: `pelan-pelan`, ipa: `po-vo-li`},{pl: `jeszcze raz`, id: `sekali lagi`, ipa: `yesh-che raz`},{pl: `gdzie`, id: `di mana`, ipa: `gje`},{pl: `co`, id: `apa`, ipa: `tso`}], phrases: [{pl: `Nie rozumiem.`, id: `Saya tidak mengerti.`, ipa: `nye ro-zu-myem`},{pl: `Proszę mówić powoli.`, id: `Tolong bicara pelan-pelan.`, ipa: `pro-she moo-vich po-vo-li`},{pl: `Jeszcze raz, proszę.`, id: `Sekali lagi, tolong.`, ipa: `yesh-che raz, pro-she`},{pl: `Czy mówisz po angielsku?`, id: `Apakah kamu berbicara bahasa Inggris?`, ipa: `chi moo-vish po an-gyel-sku`},{pl: `Potrzebuję pomocy.`, id: `Saya butuh bantuan.`, ipa: `po-tshe-boo-ye po-mo-tsi`},{pl: `Co to znaczy?`, id: `Apa artinya ini?`, ipa: `tso to zna-chi`}], grammar: `“Nie” diletakkan sebelum kata kerja untuk membuat kalimat negatif: “rozumiem” menjadi “nie rozumiem”. Untuk meminta dengan sopan, gunakan “proszę” di awal atau akhir kalimat. Di Polandia, nada sopan sangat membantu, terutama saat berbicara dengan staf stasiun, hotel, atau apotek.`, practice: [`Katakan “Nie rozumiem” tanpa terdengar panik.`,`Minta seseorang berbicara pelan-pelan dengan “Proszę mówić powoli”.`,`Gunakan “Co to znaczy?” untuk bertanya arti kata di papan informasi.`,`Gabungkan “Przepraszam” dan “Potrzebuję pomocy”.`,`Latih mengucapkan “jeszcze raz” tiga kali dengan jelas.`]},{day: 3, title: `Angka, harga, dan waktu dasar`, title_native: `Liczby, ceny i podstawowy czas`, focus: `Di Gdańsk, angka berguna untuk membeli tiket, kopi, dan memahami harga. Hari ini berfokus pada angka 0–20 dan cara bertanya harga.`, vocab: [{pl: `zero`, id: `nol`, ipa: `ze-ro`},{pl: `jeden`, id: `satu`, ipa: `ye-den`},{pl: `dwa`, id: `dua`, ipa: `dva`},{pl: `trzy`, id: `tiga`, ipa: `tshi`},{pl: `cztery`, id: `empat`, ipa: `chte-ri`},{pl: `pięć`, id: `lima`, ipa: `pyench`},{pl: `sześć`, id: `enam`, ipa: `sheshch`},{pl: `siedem`, id: `tujuh`, ipa: `she-dem`},{pl: `osiem`, id: `delapan`, ipa: `o-shem`},{pl: `dziesięć`, id: `sepuluh`, ipa: `je-shench`}], phrases: [{pl: `Ile to kosztuje?`, id: `Berapa harganya?`, ipa: `i-le to kosh-too-ye`},{pl: `To kosztuje dziesięć złotych.`, id: `Ini harganya sepuluh złoty.`, ipa: `to kosh-too-ye je-shench zwo-tih`},{pl: `Poproszę dwa bilety.`, id: `Saya minta dua tiket.`, ipa: `po-pro-she dva bi-le-ti`},{pl: `Mam pięć złotych.`, id: `Saya punya lima złoty.`, ipa: `mam pyench zwo-tih`},{pl: `Która godzina?`, id: `Jam berapa sekarang?`, ipa: `ktu-ra go-ji-na`},{pl: `Jest trzecia.`, id: `Sekarang jam tiga.`, ipa: `yest tshe-cha`}], grammar: `Dalam bahasa Polandia, angka memengaruhi bentuk kata benda, tetapi untuk tahap awal cukup hafalkan frasa umum seperti “dwa bilety” dan “dziesięć złotych”. Kata “ile” berarti “berapa” dan sangat berguna untuk harga, jumlah, dan jarak.`, practice: [`Hitung dari 0 sampai 10 dalam bahasa Polandia.`,`Pesan dua tiket dengan “Poproszę dwa bilety”.`,`Tanyakan harga barang kecil dengan “Ile to kosztuje?”.`,`Jawab dengan angka sederhana, misalnya “pięć złotych”.`,`Tanyakan waktu dengan “Która godzina?”.`]},{day: 4, title: `Di bandara dan stasiun`, title_native: `Na lotnisku i na dworcu`, focus: `Saat tiba di Warszawa Chopin Airport atau stasiun Warszawa Centralna, Anda perlu memahami papan, tiket, dan arah dasar. Hari ini membantu Anda bergerak dari titik kedatangan ke kota.`, vocab: [{pl: `lotnisko`, id: `bandara`, ipa: `lot-nis-ko`},{pl: `dworzec`, id: `stasiun kereta`, ipa: `dvo-zhets`},{pl: `pociąg`, id: `kereta`, ipa: `po-chong`},{pl: `autobus`, id: `bus`, ipa: `au-to-bus`},{pl: `bilet`, id: `tiket`, ipa: `bi-let`},{pl: `peron`, id: `peron`, ipa: `pe-ron`},{pl: `wyjście`, id: `pintu keluar`, ipa: `viy-shche`},{pl: `przylot`, id: `kedatangan`, ipa: `pshe-lot`},{pl: `odjazd`, id: `keberangkatan`, ipa: `od-yazd`},{pl: `centrum`, id: `pusat kota`, ipa: `tsen-trum`}], phrases: [{pl: `Gdzie jest wyjście?`, id: `Di mana pintu keluar?`, ipa: `gje yest viy-shche`},{pl: `Poproszę bilet do centrum.`, id: `Saya minta tiket ke pusat kota.`, ipa: `po-pro-she bi-let do tsen-trum`},{pl: `Który peron?`, id: `Peron yang mana?`, ipa: `ktu-ri pe-ron`},{pl: `Czy to pociąg do Krakowa?`, id: `Apakah ini kereta ke Kraków?`, ipa: `chi to po-chong do kra-ko-va`},{pl: `Kiedy jest odjazd?`, id: `Kapan keberangkatannya?`, ipa: `kye-di yest od-yazd`},{pl: `Gdzie jest autobus?`, id: `Di mana busnya?`, ipa: `gje yest au-to-bus`}], grammar: `“Do” berarti “ke” saat menunjukkan tujuan: “do centrum”, “do Krakowa”, “do hotelu”. Setelah “do”, bentuk nama tempat bisa berubah sedikit, tetapi Anda bisa mulai dengan menghafal frasa yang sering dipakai. Untuk bertanya lokasi, pola “Gdzie jest...?” sangat aman.`, practice: [`Tanyakan pintu keluar di bandara dengan “Gdzie jest wyjście?”.`,`Pesan tiket ke pusat kota.`,`Tanyakan apakah kereta menuju Kraków.`,`Latih kata “pociąg” sampai terdengar seperti “po-chong”.`,`Buat dua pertanyaan dengan “Gdzie jest...?”.`]},{day: 5, title: `Arah dan lokasi di kota`, title_native: `Kierunki i miejsca w mieście`, focus: `Di pusat Kraków, Anda akan sering mencari rynek, museum, atau halte tram. Hari ini melatih arah dasar dan cara memahami instruksi jalan sederhana.`, vocab: [{pl: `lewo`, id: `kiri`, ipa: `le-vo`},{pl: `prawo`, id: `kanan`, ipa: `pra-vo`},{pl: `prosto`, id: `lurus`, ipa: `pros-to`},{pl: `tutaj`, id: `di sini`, ipa: `tu-tay`},{pl: `tam`, id: `di sana`, ipa: `tam`},{pl: `blisko`, id: `dekat`, ipa: `blis-ko`},{pl: `daleko`, id: `jauh`, ipa: `da-le-ko`},{pl: `ulica`, id: `jalan`, ipa: `u-li-tsa`},{pl: `plac`, id: `alun-alun`, ipa: `plats`},{pl: `most`, id: `jembatan`, ipa: `most`}], phrases: [{pl: `Gdzie jest rynek?`, id: `Di mana pasar utama/alun-alun?`, ipa: `gje yest ri-nek`},{pl: `Proszę iść prosto.`, id: `Silakan jalan lurus.`, ipa: `pro-she ishch pros-to`},{pl: `W lewo czy w prawo?`, id: `Ke kiri atau ke kanan?`, ipa: `v le-vo chi v pra-vo`},{pl: `To jest blisko?`, id: `Apakah itu dekat?`, ipa: `to yest blis-ko`},{pl: `To jest daleko.`, id: `Itu jauh.`, ipa: `to yest da-le-ko`},{pl: `Szukam tej ulicy.`, id: `Saya mencari jalan ini.`, ipa: `shu-kam tey u-li-tsi`}], grammar: `Untuk arah, “w lewo” berarti “ke kiri” dan “w prawo” berarti “ke kanan”. Kata “proszę” juga bisa dipakai untuk memberi instruksi sopan: “Proszę iść prosto” berarti “Silakan jalan lurus”. Orang Polandia sering memberi arah dengan patokan seperti jalan, jembatan, gereja, atau alun-alun.`, practice: [`Ucapkan tiga arah: “prosto”, “w lewo”, “w prawo”.`,`Tanyakan lokasi alun-alun dengan “Gdzie jest rynek?”.`,`Tanyakan apakah suatu tempat dekat.`,`Katakan bahwa Anda mencari jalan tertentu.`,`Dengarkan atau bayangkan instruksi: lurus, kiri, kanan.`]},{day: 6, title: `Hotel dan check-in`, title_native: `Hotel i zameldowanie`, focus: `Di hotel kecil di Wrocław, Anda perlu check-in, menyebut nama, dan menanyakan kamar. Hari ini fokus pada percakapan resepsionis yang sederhana dan sopan.`, vocab: [{pl: `hotel`, id: `hotel`, ipa: `ho-tel`},{pl: `rezerwacja`, id: `reservasi`, ipa: `re-zer-va-tsya`},{pl: `pokój`, id: `kamar`, ipa: `po-kuy`},{pl: `klucz`, id: `kunci`, ipa: `klooch`},{pl: `paszport`, id: `paspor`, ipa: `pash-port`},{pl: `noc`, id: `malam`, ipa: `nots`},{pl: `łóżko`, id: `tempat tidur`, ipa: `wush-ko`},{pl: `winda`, id: `lift`, ipa: `vin-da`},{pl: `śniadanie`, id: `sarapan`, ipa: `shnya-da-nye`},{pl: `recepcja`, id: `resepsionis`, ipa: `re-tsep-tsya`}], phrases: [{pl: `Mam rezerwację.`, id: `Saya punya reservasi.`, ipa: `mam re-zer-va-tsye`},{pl: `Na nazwisko Cannon.`, id: `Atas nama Cannon.`, ipa: `na naz-vis-ko kan-non`},{pl: `Poproszę paszport.`, id: `Tolong paspornya.`, ipa: `po-pro-she pash-port`},{pl: `Gdzie jest mój pokój?`, id: `Di mana kamar saya?`, ipa: `gje yest muy po-kuy`},{pl: `Czy śniadanie jest w cenie?`, id: `Apakah sarapan termasuk harga?`, ipa: `chi shnya-da-nye yest v tse-nye`},{pl: `O której jest wymeldowanie?`, id: `Check-out jam berapa?`, ipa: `o ktu-rey yest vi-mel-do-va-nye`}], grammar: `Dalam situasi resmi, staf sering memakai bentuk sopan. Anda juga bisa tetap sederhana dengan “Dzień dobry” dan “Mam rezerwację”. Kata “mój” berarti “milik saya” untuk benda maskulin seperti “pokój”: “mój pokój”.`, practice: [`Simulasikan check-in dengan kalimat “Mam rezerwację”.`,`Tanyakan apakah sarapan termasuk.`,`Tanyakan lokasi kamar Anda.`,`Latih kata “wymeldowanie” perlahan.`,`Buat dialog pendek antara tamu dan resepsionis.`]},{day: 7, title: `Kafe dan minuman`, title_native: `Kawiarnia i napoje`, focus: `Di kafe di Poznań, Anda belajar memesan kopi, teh, air, dan roti kecil. Hari ini menekankan pola “Poproszę...” untuk memesan dengan sopan.`, vocab: [{pl: `kawa`, id: `kopi`, ipa: `ka-va`},{pl: `herbata`, id: `teh`, ipa: `her-ba-ta`},{pl: `woda`, id: `air`, ipa: `vo-da`},{pl: `mleko`, id: `susu`, ipa: `mle-ko`},{pl: `cukier`, id: `gula`, ipa: `tsu-kyer`},{pl: `ciastko`, id: `kue kecil`, ipa: `chyast-ko`},{pl: `kanapka`, id: `sandwich`, ipa: `ka-nap-ka`},{pl: `mała`, id: `kecil`, ipa: `ma-wa`},{pl: `duża`, id: `besar`, ipa: `du-zha`},{pl: `rachunek`, id: `tagihan`, ipa: `ra-hu-nek`}], phrases: [{pl: `Poproszę kawę.`, id: `Saya minta kopi.`, ipa: `po-pro-she ka-ve`},{pl: `Poproszę herbatę z cytryną.`, id: `Saya minta teh dengan lemon.`, ipa: `po-pro-she her-ba-te z tsi-tri-nom`},{pl: `Czy macie mleko?`, id: `Apakah kalian punya susu?`, ipa: `chi ma-che mle-ko`},{pl: `Bez cukru, proszę.`, id: `Tanpa gula, tolong.`, ipa: `bez tsu-kru, pro-she`},{pl: `Na miejscu czy na wynos?`, id: `Diminum di sini atau dibawa pergi?`, ipa: `na myeys-tsu chi na vi-nos`},{pl: `Poproszę rachunek.`, id: `Saya minta tagihan.`, ipa: `po-pro-she ra-hu-nek`}], grammar: `“Z” berarti “dengan”, seperti “z mlekiem” dan “z cytryną”. “Bez” berarti “tanpa”, seperti “bez cukru”. Saat memesan, “Poproszę...” adalah bentuk sangat praktis dan sopan, mirip “Saya minta...”.`, practice: [`Pesan kopi dengan “Poproszę kawę”.`,`Ubah pesanan menjadi teh dengan lemon.`,`Katakan “tanpa gula” dalam bahasa Polandia.`,`Jawab pilihan “na miejscu czy na wynos”.`,`Minta tagihan di akhir pesanan.`]},{day: 8, title: `Makanan Polandia dasar`, title_native: `Podstawowe polskie jedzenie`, focus: `Di bar mleczny di Kraków, Anda bertemu makanan khas seperti pierogi dan zupa. Hari ini membantu Anda membaca menu sederhana dan memesan makanan populer.`, vocab: [{pl: `jedzenie`, id: `makanan`, ipa: `ye-dze-nye`},{pl: `menu`, id: `menu`, ipa: `me-nu`},{pl: `zupa`, id: `sup`, ipa: `zu-pa`},{pl: `pierogi`, id: `pierogi / pangsit Polandia`, ipa: `pye-ro-gi`},{pl: `chleb`, id: `roti`, ipa: `hlep`},{pl: `ser`, id: `keju`, ipa: `ser`},{pl: `mięso`, id: `daging`, ipa: `myen-so`},{pl: `ryba`, id: `ikan`, ipa: `ri-ba`},{pl: `warzywa`, id: `sayuran`, ipa: `va-zhi-va`},{pl: `smaczne`, id: `enak`, ipa: `smach-ne`}], phrases: [{pl: `Co pan poleca?`, id: `Apa yang Bapak rekomendasikan?`, ipa: `tso pan po-le-tsa`},{pl: `Co pani poleca?`, id: `Apa yang Ibu rekomendasikan?`, ipa: `tso pa-ni po-le-tsa`},{pl: `Poproszę pierogi.`, id: `Saya minta pierogi.`, ipa: `po-pro-she pye-ro-gi`},{pl: `Czy to jest z mięsem?`, id: `Apakah ini dengan daging?`, ipa: `chi to yest z myen-sem`},{pl: `To jest bardzo smaczne.`, id: `Ini sangat enak.`, ipa: `to yest bar-dzo smach-ne`},{pl: `Nie jem mięsa.`, id: `Saya tidak makan daging.`, ipa: `nye yem myen-sa`}], grammar: `“Pan” digunakan untuk laki-laki dewasa secara sopan, dan “pani” untuk perempuan dewasa. Untuk bertanya rekomendasi, pilih “Co pan poleca?” atau “Co pani poleca?” sesuai lawan bicara. Kata “jem” berarti “saya makan”, jadi “Nie jem mięsa” sangat penting bagi vegetarian.`, practice: [`Pesan pierogi dengan sopan.`,`Tanyakan apakah makanan mengandung daging.`,`Katakan bahwa makanan itu enak.`,`Tanyakan rekomendasi kepada pelayan laki-laki dan perempuan.`,`Buat kalimat tentang satu makanan yang Anda makan atau tidak makan.`]},{day: 9, title: `Restoran dan reservasi`, title_native: `Restauracja i rezerwacja`, focus: `Di restoran di Gdańsk, Anda perlu meminta meja, melihat menu, dan menyebut jumlah orang. Hari ini mempersiapkan Anda untuk makan malam santai atau sedikit formal.`, vocab: [{pl: `restauracja`, id: `restoran`, ipa: `res-tau-ra-tsya`},{pl: `stolik`, id: `meja`, ipa: `sto-lik`},{pl: `osoba`, id: `orang`, ipa: `o-so-ba`},{pl: `kelner`, id: `pelayan laki-laki`, ipa: `kel-ner`},{pl: `kelnerka`, id: `pelayan perempuan`, ipa: `kel-ner-ka`},{pl: `danie`, id: `hidangan`, ipa: `da-nye`},{pl: `deser`, id: `pencuci mulut`, ipa: `de-ser`},{pl: `napój`, id: `minuman`, ipa: `na-puy`},{pl: `widelec`, id: `garpu`, ipa: `vi-de-lets`},{pl: `nóż`, id: `pisau`, ipa: `nush`}], phrases: [{pl: `Stolik dla dwóch osób, proszę.`, id: `Meja untuk dua orang, tolong.`, ipa: `sto-lik dla dvuh o-sub, pro-she`},{pl: `Czy macie wolny stolik?`, id: `Apakah ada meja kosong?`, ipa: `chi ma-che vol-ni sto-lik`},{pl: `Poproszę menu.`, id: `Saya minta menu.`, ipa: `po-pro-she me-nu`},{pl: `Jeszcze chwilę, proszę.`, id: `Sebentar lagi, tolong.`, ipa: `yesh-che hfi-le, pro-she`},{pl: `To wszystko, dziękuję.`, id: `Itu saja, terima kasih.`, ipa: `to fshist-ko, jen-koo-ye`},{pl: `Czy mogę zapłacić kartą?`, id: `Apakah saya bisa bayar dengan kartu?`, ipa: `chi mo-ge za-pwa-chich kar-tom`}], grammar: `“Dla” berarti “untuk”, seperti “dla dwóch osób” yaitu “untuk dua orang”. “Mogę” berarti “saya bisa” atau “bolehkah saya”, sangat berguna untuk permintaan sopan. Di restoran, “Jeszcze chwilę” berarti Anda butuh sedikit waktu sebelum memesan.`, practice: [`Minta meja untuk dua orang.`,`Tanyakan apakah ada meja kosong.`,`Minta menu.`,`Katakan bahwa Anda butuh waktu sebentar.`,`Tanyakan apakah bisa membayar dengan kartu.`]},{day: 10, title: `Membayar dan uang`, title_native: `Płacenie i pieniądze`, focus: `Di toko atau restoran di Łódź, Anda perlu memilih pembayaran tunai atau kartu. Hari ini melatih frasa tentang uang, pembayaran, struk, dan kembalian.`, vocab: [{pl: `pieniądze`, id: `uang`, ipa: `pye-nyon-dze`},{pl: `gotówka`, id: `uang tunai`, ipa: `go-toof-ka`},{pl: `karta`, id: `kartu`, ipa: `kar-ta`},{pl: `paragon`, id: `struk`, ipa: `pa-ra-gon`},{pl: `reszta`, id: `kembalian`, ipa: `resh-ta`},{pl: `cena`, id: `harga`, ipa: `tse-na`},{pl: `drogo`, id: `mahal`, ipa: `dro-go`},{pl: `tanio`, id: `murah`, ipa: `ta-nyo`},{pl: `bankomat`, id: `ATM`, ipa: `ban-ko-mat`},{pl: `płatność`, id: `pembayaran`, ipa: `pwat-noshch`}], phrases: [{pl: `Kartą, proszę.`, id: `Dengan kartu, tolong.`, ipa: `kar-tom, pro-she`},{pl: `Gotówką, proszę.`, id: `Dengan tunai, tolong.`, ipa: `go-toof-kom, pro-she`},{pl: `Czy mogę dostać paragon?`, id: `Bisa saya dapat struk?`, ipa: `chi mo-ge dos-tach pa-ra-gon`},{pl: `Gdzie jest bankomat?`, id: `Di mana ATM?`, ipa: `gje yest ban-ko-mat`},{pl: `To za drogo.`, id: `Itu terlalu mahal.`, ipa: `to za dro-go`},{pl: `Reszty nie trzeba.`, id: `Tidak perlu kembalian.`, ipa: `resh-ti nye tshe-ba`}], grammar: `Akhiran “-ą” sering terdengar saat mengatakan “dengan sesuatu”, seperti “kartą” dan “gotówką”. Frasa “nie trzeba” berarti “tidak perlu”. Untuk transaksi kecil, “Kartą, proszę” sudah cukup jelas dan sopan.`, practice: [`Katakan Anda ingin membayar dengan kartu.`,`Minta struk dengan sopan.`,`Tanyakan lokasi ATM.`,`Katakan bahwa harga terlalu mahal.`,`Latih “Reszty nie trzeba” untuk situasi memberi tip.`]},{day: 11, title: `Transportasi umum`, title_native: `Komunikacja miejska`, focus: `Di Warszawa, transportasi umum mencakup tram, metro, bus, dan kereta kota. Hari ini membantu Anda membeli tiket, bertanya jalur, dan memahami pemberhentian.`, vocab: [{pl: `tramwaj`, id: `trem`, ipa: `tram-vay`},{pl: `metro`, id: `metro`, ipa: `me-tro`},{pl: `przystanek`, id: `halte`, ipa: `pshi-sta-nek`},{pl: `linia`, id: `jalur`, ipa: `li-nya`},{pl: `biletomat`, id: `mesin tiket`, ipa: `bi-le-to-mat`},{pl: `kontroler`, id: `pemeriksa tiket`, ipa: `kon-tro-ler`},{pl: `ważny`, id: `valid`, ipa: `vazh-ni`},{pl: `ulgowy`, id: `diskon`, ipa: `ul-go-vi`},{pl: `normalny`, id: `reguler`, ipa: `nor-mal-ni`},{pl: `przesiadka`, id: `pindah transportasi`, ipa: `pshe-shad-ka`}], phrases: [{pl: `Gdzie jest przystanek tramwajowy?`, id: `Di mana halte trem?`, ipa: `gje yest pshi-sta-nek tram-va-yo-vi`},{pl: `Poproszę bilet normalny.`, id: `Saya minta tiket reguler.`, ipa: `po-pro-she bi-let nor-mal-ni`},{pl: `Czy ten bilet jest ważny?`, id: `Apakah tiket ini valid?`, ipa: `chi ten bi-let yest vazh-ni`},{pl: `Która linia jedzie do centrum?`, id: `Jalur mana yang menuju pusat kota?`, ipa: `ktu-ra li-nya ye-je do tsen-trum`},{pl: `Muszę się przesiąść?`, id: `Apakah saya harus pindah?`, ipa: `mu-she shye pshe-shonshch`},{pl: `To mój przystanek.`, id: `Ini halte saya.`, ipa: `to muy pshi-sta-nek`}], grammar: `“Ten” berarti “ini/itu” untuk kata benda maskulin, seperti “ten bilet”. Kata “muszę” berarti “saya harus”, dan bisa dipakai untuk kebutuhan praktis: “Muszę się przesiąść?” berarti “Apakah saya harus transit/pindah?”. Di kota besar Polandia, validasi tiket sangat penting.`, practice: [`Tanyakan halte trem terdekat.`,`Minta tiket reguler.`,`Tanyakan apakah tiket Anda valid.`,`Tanyakan jalur ke pusat kota.`,`Katakan “To mój przystanek” saat turun.`]},{day: 12, title: `Taksi dan ride-hailing`, title_native: `Taksówka i przejazd`, focus: `Di malam hari di Wrocław, Anda mungkin mengambil taksi atau mobil aplikasi. Hari ini melatih alamat, tujuan, estimasi waktu, dan percakapan singkat dengan pengemudi.`, vocab: [{pl: `taksówka`, id: `taksi`, ipa: `tak-soof-ka`},{pl: `adres`, id: `alamat`, ipa: `a-dres`},{pl: `kierowca`, id: `pengemudi`, ipa: `kye-rov-tsa`},{pl: `hotel`, id: `hotel`, ipa: `ho-tel`},{pl: `lotnisko`, id: `bandara`, ipa: `lot-nis-ko`},{pl: `szybko`, id: `cepat`, ipa: `shib-ko`},{pl: `wolno`, id: `pelan`, ipa: `vol-no`},{pl: `minuta`, id: `menit`, ipa: `mi-nu-ta`},{pl: `ruch`, id: `lalu lintas`, ipa: `ruh`},{pl: `proszę czekać`, id: `mohon tunggu`, ipa: `pro-she che-kach`}], phrases: [{pl: `Proszę jechać pod ten adres.`, id: `Tolong pergi ke alamat ini.`, ipa: `pro-she ye-hach pot ten a-dres`},{pl: `Ile to zajmie?`, id: `Berapa lama ini akan memakan waktu?`, ipa: `i-le to zay-mye`},{pl: `Proszę tutaj skręcić.`, id: `Tolong belok di sini.`, ipa: `pro-she tu-tay skren-chich`},{pl: `Czy może pan poczekać?`, id: `Bisakah Bapak menunggu?`, ipa: `chi mo-zhe pan po-che-kach`},{pl: `Jadę na lotnisko.`, id: `Saya pergi ke bandara.`, ipa: `ya-de na lot-nis-ko`},{pl: `Proszę mnie wysadzić tutaj.`, id: `Tolong turunkan saya di sini.`, ipa: `pro-she mnye vi-sa-jich tu-tay`}], grammar: `“Jadę” berarti “saya pergi” dengan kendaraan. Untuk tujuan, gunakan “do” untuk kota/tempat tertutup seperti hotel, dan “na” untuk beberapa tempat seperti “na lotnisko”. Dalam praktik, frasa lengkap “Jadę na lotnisko” mudah dipahami.`, practice: [`Tunjukkan alamat dan katakan “Proszę jechać pod ten adres”.`,`Tanyakan durasi perjalanan.`,`Minta pengemudi menurunkan Anda di sini.`,`Katakan Anda pergi ke bandara.`,`Latih kata “skręcić” untuk belok.`]},{day: 13, title: `Belanja kebutuhan harian`, title_native: `Zakupy codzienne`, focus: `Di supermarket di Poznań, Anda membeli air, roti, buah, dan barang kecil. Hari ini melatih kosakata belanja serta pertanyaan tentang ketersediaan barang.`, vocab: [{pl: `sklep`, id: `toko`, ipa: `sklep`},{pl: `supermarket`, id: `supermarket`, ipa: `su-per-mar-ket`},{pl: `koszyk`, id: `keranjang`, ipa: `ko-shik`},{pl: `torba`, id: `tas`, ipa: `tor-ba`},{pl: `chleb`, id: `roti`, ipa: `hlep`},{pl: `owoce`, id: `buah-buahan`, ipa: `o-vo-tse`},{pl: `jabłko`, id: `apel`, ipa: `yab-wko`},{pl: `banan`, id: `pisang`, ipa: `ba-nan`},{pl: `woda`, id: `air`, ipa: `vo-da`},{pl: `mleko`, id: `susu`, ipa: `mle-ko`}], phrases: [{pl: `Gdzie jest chleb?`, id: `Di mana roti?`, ipa: `gje yest hlep`},{pl: `Czy macie wodę?`, id: `Apakah kalian punya air?`, ipa: `chi ma-che vo-de`},{pl: `Poproszę torbę.`, id: `Saya minta tas.`, ipa: `po-pro-she tor-be`},{pl: `Ile kosztuje jabłko?`, id: `Berapa harga apel?`, ipa: `i-le kosh-too-ye yab-wko`},{pl: `Szukam mleka.`, id: `Saya mencari susu.`, ipa: `shu-kam mle-ka`},{pl: `To wszystko.`, id: `Itu saja.`, ipa: `to fshist-ko`}], grammar: `“Szukam” berarti “saya mencari”, tetapi kata setelahnya sering berubah bentuk, seperti “mleka” dari “mleko”. Jangan khawatir dulu; dalam toko, orang tetap akan mengerti. Fokus pada pola “Szukam...” dan nama barang.`, practice: [`Tanyakan lokasi roti di toko.`,`Katakan Anda mencari susu.`,`Minta tas di kasir.`,`Tanyakan harga apel.`,`Buat daftar belanja 5 barang dalam bahasa Polandia.`]},{day: 14, title: `Pakaian dan ukuran`, title_native: `Ubrania i rozmiary`, focus: `Di mal di Warszawa, Anda mungkin ingin membeli jaket, sepatu, atau baju hangat. Hari ini melatih ukuran, warna dasar, dan meminta mencoba pakaian.`, vocab: [{pl: `ubranie`, id: `pakaian`, ipa: `u-bra-nye`},{pl: `koszula`, id: `kemeja`, ipa: `ko-shu-la`},{pl: `spodnie`, id: `celana`, ipa: `spod-nye`},{pl: `kurtka`, id: `jaket`, ipa: `kurt-ka`},{pl: `buty`, id: `sepatu`, ipa: `bu-ti`},{pl: `rozmiar`, id: `ukuran`, ipa: `roz-myar`},{pl: `mały`, id: `kecil`, ipa: `ma-wi`},{pl: `duży`, id: `besar`, ipa: `du-zhi`},{pl: `czarny`, id: `hitam`, ipa: `char-ni`},{pl: `biały`, id: `putih`, ipa: `bya-wi`}], phrases: [{pl: `Jaki to rozmiar?`, id: `Ini ukuran apa?`, ipa: `ya-ki to roz-myar`},{pl: `Czy mogę przymierzyć?`, id: `Bolehkah saya mencoba?`, ipa: `chi mo-ge pshi-mye-zhich`},{pl: `Szukam kurtki.`, id: `Saya mencari jaket.`, ipa: `shu-kam kurt-ki`},{pl: `Macie większy rozmiar?`, id: `Apakah ada ukuran lebih besar?`, ipa: `ma-che vyen-kshi roz-myar`},{pl: `Macie mniejszy rozmiar?`, id: `Apakah ada ukuran lebih kecil?`, ipa: `ma-che mnye-shi roz-myar`},{pl: `Wezmę to.`, id: `Saya ambil ini.`, ipa: `vez-me to`}], grammar: `“Jaki” berarti “apa/yang mana” untuk kata benda maskulin, seperti “rozmiar”. Untuk meminta izin, “Czy mogę...?” adalah pola sangat berguna: “Czy mogę przymierzyć?” berarti “Bolehkah saya mencoba?”. Di toko pakaian, “Wezmę to” berarti Anda memutuskan membeli.`, practice: [`Tanyakan ukuran pakaian.`,`Minta izin mencoba jaket.`,`Tanyakan ukuran lebih besar.`,`Tanyakan ukuran lebih kecil.`,`Katakan “Wezmę to” setelah memilih barang.`]},{day: 15, title: `Cuaca dan pakaian harian`, title_native: `Pogoda i codzienne ubrania`, focus: `Di Zakopane atau Kraków, cuaca bisa berubah cepat, terutama di musim dingin atau pegunungan. Hari ini membantu Anda membicarakan hujan, dingin, panas, dan kebutuhan pakaian.`, vocab: [{pl: `pogoda`, id: `cuaca`, ipa: `po-go-da`},{pl: `deszcz`, id: `hujan`, ipa: `deshch`},{pl: `śnieg`, id: `salju`, ipa: `shnyek`},{pl: `słońce`, id: `matahari`, ipa: `swoin-tse`},{pl: `zimno`, id: `dingin`, ipa: `zim-no`},{pl: `ciepło`, id: `hangat`, ipa: `chep-wo`},{pl: `gorąco`, id: `panas`, ipa: `go-ron-tso`},{pl: `wiatr`, id: `angin`, ipa: `vyatr`},{pl: `parasol`, id: `payung`, ipa: `pa-ra-sol`},{pl: `sweter`, id: `sweter`, ipa: `sve-ter`}], phrases: [{pl: `Jaka jest pogoda?`, id: `Bagaimana cuacanya?`, ipa: `ya-ka yest po-go-da`},{pl: `Pada deszcz.`, id: `Hujan turun.`, ipa: `pa-da deshch`},{pl: `Jest zimno.`, id: `Cuacanya dingin.`, ipa: `yest zim-no`},{pl: `Jest bardzo gorąco.`, id: `Cuacanya sangat panas.`, ipa: `yest bar-dzo go-ron-tso`},{pl: `Potrzebuję parasola.`, id: `Saya butuh payung.`, ipa: `po-tshe-boo-ye pa-ra-so-la`},{pl: `Mam sweter.`, id: `Saya punya sweter.`, ipa: `mam sve-ter`}], grammar: `Untuk cuaca, bahasa Polandia sering memakai “jest” seperti “Jest zimno” atau “Jest ciepło”. “Pada” berarti “turun” untuk hujan atau salju: “Pada deszcz” dan “Pada śnieg”. Frasa cuaca sangat sering muncul dalam small talk.`, practice: [`Tanyakan cuaca hari ini.`,`Katakan bahwa cuaca dingin.`,`Katakan bahwa hujan turun.`,`Katakan Anda butuh payung.`,`Buat tiga kalimat cuaca dengan “jest”.`]},{day: 16, title: `Kesehatan dan apotek`, title_native: `Zdrowie i apteka`, focus: `Di apotek di Gdańsk, Anda perlu menjelaskan sakit kepala, demam, atau perut tidak enak. Hari ini melatih kata kesehatan penting dan permintaan obat sederhana.`, vocab: [{pl: `apteka`, id: `apotek`, ipa: `ap-te-ka`},{pl: `lekarz`, id: `dokter`, ipa: `le-kash`},{pl: `lek`, id: `obat`, ipa: `lek`},{pl: `ból`, id: `rasa sakit`, ipa: `bul`},{pl: `głowa`, id: `kepala`, ipa: `gwo-va`},{pl: `brzuch`, id: `perut`, ipa: `bzhuh`},{pl: `gardło`, id: `tenggorokan`, ipa: `gar-dwo`},{pl: `gorączka`, id: `demam`, ipa: `go-ronch-ka`},{pl: `alergia`, id: `alergi`, ipa: `a-ler-gya`},{pl: `recepta`, id: `resep`, ipa: `re-tsep-ta`}], phrases: [{pl: `Boli mnie głowa.`, id: `Kepala saya sakit.`, ipa: `bo-li mnye gwo-va`},{pl: `Boli mnie brzuch.`, id: `Perut saya sakit.`, ipa: `bo-li mnye bzhuh`},{pl: `Mam gorączkę.`, id: `Saya demam.`, ipa: `mam go-ronch-ke`},{pl: `Potrzebuję leku.`, id: `Saya butuh obat.`, ipa: `po-tshe-boo-ye le-ku`},{pl: `Czy potrzebuję recepty?`, id: `Apakah saya perlu resep?`, ipa: `chi po-tshe-boo-ye re-tsep-ti`},{pl: `Mam alergię.`, id: `Saya punya alergi.`, ipa: `mam a-ler-gye`}], grammar: `Pola “Boli mnie...” berarti “... saya sakit”, tetapi urutannya berbeda dari bahasa Indonesia. “Boli mnie głowa” secara harfiah seperti “kepala menyakitiku”. Untuk kebutuhan medis, gunakan kalimat pendek dan jelas agar apoteker atau dokter cepat memahami.`, practice: [`Katakan bahwa kepala Anda sakit.`,`Katakan bahwa perut Anda sakit.`,`Tanyakan apakah perlu resep.`,`Jelaskan bahwa Anda demam.`,`Sebutkan satu alergi dengan pola “Mam alergię na...”.`]},{day: 17, title: `Keadaan darurat`, title_native: `Nagłe wypadki`, focus: `Di perjalanan, Anda harus siap untuk situasi mendesak seperti kehilangan paspor, sakit parah, atau perlu polisi. Hari ini berfokus pada frasa darurat yang jelas dan langsung.`, vocab: [{pl: `policja`, id: `polisi`, ipa: `po-li-tsya`},{pl: `szpital`, id: `rumah sakit`, ipa: `shpi-tal`},{pl: `ambulans`, id: `ambulans`, ipa: `am-bu-lans`},{pl: `pomocy`, id: `tolong`, ipa: `po-mo-tsi`},{pl: `wypadek`, id: `kecelakaan`, ipa: `vi-pa-dek`},{pl: `paszport`, id: `paspor`, ipa: `pash-port`},{pl: `telefon`, id: `telepon`, ipa: `te-le-fon`},{pl: `zagubiony`, id: `hilang / tersesat`, ipa: `za-gu-byo-ni`},{pl: `kradzież`, id: `pencurian`, ipa: `kra-jyesh`},{pl: `niebezpieczne`, id: `berbahaya`, ipa: `nye-bez-pyech-ne`}], phrases: [{pl: `Pomocy!`, id: `Tolong!`, ipa: `po-mo-tsi`},{pl: `Proszę wezwać policję.`, id: `Tolong panggil polisi.`, ipa: `pro-she vez-vach po-li-tsye`},{pl: `Proszę wezwać ambulans.`, id: `Tolong panggil ambulans.`, ipa: `pro-she vez-vach am-bu-lans`},{pl: `Zgubiłem paszport.`, id: `Saya kehilangan paspor.`, ipa: `zgu-bi-wem pash-port`},{pl: `Zgubiłam paszport.`, id: `Saya kehilangan paspor.`, ipa: `zgu-bi-wam pash-port`},{pl: `To nagły wypadek.`, id: `Ini keadaan darurat.`, ipa: `to nag-wi vi-pa-dek`}], grammar: `Dalam bahasa Polandia, beberapa bentuk masa lampau berubah menurut gender pembicara. Laki-laki mengatakan “zgubiłem”, perempuan mengatakan “zgubiłam”. Dalam darurat, yang paling penting adalah kata inti seperti “Pomocy”, “policja”, “ambulans”, dan “szpital”.`, practice: [`Latih mengucapkan “Pomocy!” dengan jelas.`,`Katakan bahwa Anda kehilangan paspor dengan bentuk yang sesuai.`,`Minta seseorang memanggil polisi.`,`Minta seseorang memanggil ambulans.`,`Ulangi “To nagły wypadek” sampai lancar.`]},{day: 18, title: `Orang, keluarga, dan teman`, title_native: `Ludzie, rodzina i przyjaciele`, focus: `Saat berbincang dengan orang lokal di Lublin atau Poznań, topik keluarga dan teman sering muncul. Hari ini memberi Anda kosakata sosial dasar yang hangat dan sopan.`, vocab: [{pl: `człowiek`, id: `orang / manusia`, ipa: `chwo-vyek`},{pl: `kobieta`, id: `perempuan`, ipa: `ko-bye-ta`},{pl: `mężczyzna`, id: `laki-laki`, ipa: `men-shchi-zna`},{pl: `dziecko`, id: `anak`, ipa: `jech-ko`},{pl: `rodzina`, id: `keluarga`, ipa: `ro-ji-na`},{pl: `mama`, id: `ibu`, ipa: `ma-ma`},{pl: `tata`, id: `ayah`, ipa: `ta-ta`},{pl: `przyjaciel`, id: `teman dekat laki-laki`, ipa: `pshi-ya-chel`},{pl: `przyjaciółka`, id: `teman dekat perempuan`, ipa: `pshi-ya-chuw-ka`},{pl: `znajomy`, id: `kenalan`, ipa: `zna-yo-mi`}], phrases: [{pl: `To moja rodzina.`, id: `Ini keluarga saya.`, ipa: `to mo-ya ro-ji-na`},{pl: `Mam brata.`, id: `Saya punya saudara laki-laki.`, ipa: `mam bra-ta`},{pl: `Mam siostrę.`, id: `Saya punya saudara perempuan.`, ipa: `mam sho-stre`},{pl: `To mój przyjaciel.`, id: `Ini teman dekat laki-laki saya.`, ipa: `to muy pshi-ya-chel`},{pl: `To moja przyjaciółka.`, id: `Ini teman dekat perempuan saya.`, ipa: `to mo-ya pshi-ya-chuw-ka`},{pl: `Czy masz rodzinę w Polsce?`, id: `Apakah kamu punya keluarga di Polandia?`, ipa: `chi mash ro-ji-ne v pol-sche`}], grammar: `“Mój” dipakai untuk kata benda maskulin, dan “moja” untuk feminin. Contohnya “mój przyjaciel” tetapi “moja rodzina”. Bahasa Polandia memiliki gender kata benda, jadi perhatikan pasangan yang sering muncul daripada menghafal semua aturan sekaligus.`, practice: [`Perkenalkan keluarga Anda dengan “To moja rodzina”.`,`Katakan apakah Anda punya saudara laki-laki atau perempuan.`,`Perkenalkan teman dekat laki-laki dan perempuan.`,`Tanyakan apakah seseorang punya keluarga di Polandia.`,`Buat tiga kalimat memakai “mój” dan “moja”.`]},{day: 19, title: `Small talk dan sopan santun`, title_native: `Small talk i uprzejmość`, focus: `Di taman atau kafe di Kraków, percakapan ringan bisa dimulai dari cuaca, perjalanan, atau kota. Hari ini melatih respons pendek yang terdengar alami dan sopan.`, vocab: [{pl: `miły`, id: `baik / menyenangkan`, ipa: `mi-wi`},{pl: `ładny`, id: `bagus / indah`, ipa: `wad-ni`},{pl: `ciekawy`, id: `menarik`, ipa: `che-ka-vi`},{pl: `podróż`, id: `perjalanan`, ipa: `po-droosh`},{pl: `miasto`, id: `kota`, ipa: `myas-to`},{pl: `kraj`, id: `negara`, ipa: `kray`},{pl: `lubię`, id: `saya suka`, ipa: `lu-bye`},{pl: `bardzo`, id: `sangat`, ipa: `bar-dzo`},{pl: `trochę`, id: `sedikit`, ipa: `tro-he`},{pl: `naprawdę`, id: `benar-benar`, ipa: `na-praf-de`}], phrases: [{pl: `Bardzo mi miło.`, id: `Senang sekali bertemu Anda.`, ipa: `bar-dzo mi mi-wo`},{pl: `Lubię Polskę.`, id: `Saya suka Polandia.`, ipa: `lu-bye pol-ske`},{pl: `To piękne miasto.`, id: `Ini kota yang indah.`, ipa: `to pyenk-ne myas-to`},{pl: `Jestem tu pierwszy raz.`, id: `Saya di sini pertama kali.`, ipa: `yes-tem tu pyerf-shi raz`},{pl: `Mówię trochę po polsku.`, id: `Saya berbicara sedikit bahasa Polandia.`, ipa: `moo-vye tro-he po pol-sku`},{pl: `Naprawdę?`, id: `Benarkah?`, ipa: `na-praf-de`}], grammar: `“Lubię” berarti “saya suka” dan dapat diikuti kata benda: “Lubię Polskę”, “Lubię kawę”. Untuk menunjukkan kemampuan bahasa, gunakan “Mówię trochę po polsku”. Frasa sederhana ini sering membuat orang lokal tersenyum karena Anda mencoba memakai bahasa mereka.`, practice: [`Katakan bahwa Anda suka Polandia.`,`Katakan bahwa Anda berada di kota itu untuk pertama kali.`,`Puji kota dengan “To piękne miasto”.`,`Katakan Anda berbicara sedikit bahasa Polandia.`,`Gunakan “Naprawdę?” sebagai respons alami dalam percakapan.`]},{day: 20, title: `Hari, tanggal, dan rencana`, title_native: `Dni, daty i plany`, focus: `Saat membuat rencana di Warszawa, Anda perlu menyebut hari, besok, hari ini, dan jam. Hari ini membantu Anda mengatur jadwal sederhana seperti tur, makan malam, atau museum.`, vocab: [{pl: `dzisiaj`, id: `hari ini`, ipa: `ji-shay`},{pl: `jutro`, id: `besok`, ipa: `yu-tro`},{pl: `wczoraj`, id: `kemarin`, ipa: `fcho-ray`},{pl: `poniedziałek`, id: `Senin`, ipa: `po-nye-ja-wek`},{pl: `wtorek`, id: `Selasa`, ipa: `fto-rek`},{pl: `środa`, id: `Rabu`, ipa: `shro-da`},{pl: `czwartek`, id: `Kamis`, ipa: `chfar-tek`},{pl: `piątek`, id: `Jumat`, ipa: `pyon-tek`},{pl: `sobota`, id: `Sabtu`, ipa: `so-bo-ta`},{pl: `niedziela`, id: `Minggu`, ipa: `nye-je-la`}], phrases: [{pl: `Dzisiaj idę do muzeum.`, id: `Hari ini saya pergi ke museum.`, ipa: `ji-shay i-de do mu-ze-um`},{pl: `Jutro jadę do Krakowa.`, id: `Besok saya pergi ke Kraków.`, ipa: `yu-tro ya-de do kra-ko-va`},{pl: `W piątek mam rezerwację.`, id: `Pada hari Jumat saya punya reservasi.`, ipa: `f pyon-tek mam re-zer-va-tsye`},{pl: `O której godzinie?`, id: `Pada jam berapa?`, ipa: `o ktu-rey go-ji-nye`},{pl: `Mam czas wieczorem.`, id: `Saya punya waktu malam hari.`, ipa: `mam chas vye-cho-rem`},{pl: `Nie mam czasu.`, id: `Saya tidak punya waktu.`, ipa: `nye mam cha-su`}], grammar: `Untuk hari, bahasa Polandia sering memakai “w” sebelum nama hari: “w piątek”, “w sobotę”. “Idę” digunakan untuk pergi berjalan kaki atau secara umum, sementara “jadę” lebih jelas berarti pergi dengan kendaraan. Untuk rencana sederhana, “mam czas” dan “nie mam czasu” sangat berguna.`, practice: [`Sebutkan hari ini, besok, dan kemarin.`,`Buat kalimat “Dzisiaj idę do...”.`,`Buat kalimat “Jutro jadę do...”.`,`Tanyakan jam rencana dimulai.`,`Katakan Anda punya atau tidak punya waktu.`]},{day: 21, title: `Mengunjungi museum dan tempat wisata`, title_native: `Muzea i atrakcje turystyczne`, focus: `Di museum di Warszawa atau Kraków, Anda perlu membeli tiket, bertanya jam buka, dan memahami aturan foto. Hari ini menyiapkan Anda untuk tempat wisata budaya.`, vocab: [{pl: `muzeum`, id: `museum`, ipa: `mu-ze-um`},{pl: `zamek`, id: `kastel`, ipa: `za-mek`},{pl: `kościół`, id: `gereja`, ipa: `ko-shchuw`},{pl: `bilet`, id: `tiket`, ipa: `bi-let`},{pl: `wystawa`, id: `pameran`, ipa: `vis-ta-va`},{pl: `wejście`, id: `pintu masuk`, ipa: `vey-shche`},{pl: `zdjęcie`, id: `foto`, ipa: `zdjen-che`},{pl: `otwarte`, id: `buka`, ipa: `ot-far-te`},{pl: `zamknięte`, id: `tutup`, ipa: `zamk-nye-te`},{pl: `przewodnik`, id: `pemandu`, ipa: `pshe-vod-nik`}], phrases: [{pl: `Ile kosztuje bilet?`, id: `Berapa harga tiket?`, ipa: `i-le kosh-too-ye bi-let`},{pl: `Czy muzeum jest otwarte?`, id: `Apakah museum buka?`, ipa: `chi mu-ze-um yest ot-far-te`},{pl: `O której zamykacie?`, id: `Kalian tutup jam berapa?`, ipa: `o ktu-rey za-mi-ka-che`},{pl: `Czy można robić zdjęcia?`, id: `Boleh mengambil foto?`, ipa: `chi mozh-na ro-bich zdjen-cha`},{pl: `Poproszę jeden bilet.`, id: `Saya minta satu tiket.`, ipa: `po-pro-she ye-den bi-let`},{pl: `Czy jest przewodnik po angielsku?`, id: `Apakah ada pemandu dalam bahasa Inggris?`, ipa: `chi yest pshe-vod-nik po an-gyel-sku`}], grammar: `“Można” berarti “boleh/bisa” secara umum dan sangat berguna untuk aturan: “Czy można robić zdjęcia?” berarti “Apakah boleh mengambil foto?”. “Otwarte” dan “zamknięte” sering terlihat di pintu toko, museum, dan restoran.`, practice: [`Tanyakan apakah museum buka.`,`Tanyakan harga tiket.`,`Minta satu tiket.`,`Tanyakan apakah boleh mengambil foto.`,`Tanyakan apakah ada pemandu bahasa Inggris.`]},{day: 22, title: `Internet, telepon, dan masalah teknis`, title_native: `Internet, telefon i problemy techniczne`, focus: `Di perjalanan modern, Anda perlu Wi-Fi, pengisi daya, dan kadang kartu SIM. Hari ini melatih frasa untuk koneksi internet, baterai, dan bantuan teknis sederhana.`, vocab: [{pl: `internet`, id: `internet`, ipa: `in-ter-net`},{pl: `Wi-Fi`, id: `Wi-Fi`, ipa: `vay-fay`},{pl: `hasło`, id: `kata sandi`, ipa: `has-wo`},{pl: `telefon`, id: `telepon`, ipa: `te-le-fon`},{pl: `ładowarka`, id: `charger`, ipa: `wa-do-var-ka`},{pl: `bateria`, id: `baterai`, ipa: `ba-te-rya`},{pl: `karta SIM`, id: `kartu SIM`, ipa: `kar-ta sim`},{pl: `problem`, id: `masalah`, ipa: `pro-blem`},{pl: `działa`, id: `berfungsi`, ipa: `ja-wa`},{pl: `nie działa`, id: `tidak berfungsi`, ipa: `nye ja-wa`}], phrases: [{pl: `Jakie jest hasło do Wi-Fi?`, id: `Apa kata sandi Wi-Fi?`, ipa: `ya-kye yest has-wo do vay-fay`},{pl: `Internet nie działa.`, id: `Internet tidak berfungsi.`, ipa: `in-ter-net nye ja-wa`},{pl: `Potrzebuję ładowarki.`, id: `Saya butuh charger.`, ipa: `po-tshe-boo-ye wa-do-var-ki`},{pl: `Mój telefon nie działa.`, id: `Telepon saya tidak berfungsi.`, ipa: `muy te-le-fon nye ja-wa`},{pl: `Gdzie mogę kupić kartę SIM?`, id: `Di mana saya bisa membeli kartu SIM?`, ipa: `gje mo-ge ku-pich kar-te sim`},{pl: `Czy mogę tu naładować telefon?`, id: `Bolehkah saya mengisi daya telepon di sini?`, ipa: `chi mo-ge tu na-wa-do-vach te-le-fon`}], grammar: `“Nie działa” adalah frasa penting untuk segala sesuatu yang rusak atau tidak berfungsi. Kata “mój” berarti “milik saya”, seperti “mój telefon”. Untuk bertanya “di mana saya bisa...”, gunakan “Gdzie mogę...?” diikuti kata kerja.`, practice: [`Tanyakan kata sandi Wi-Fi.`,`Katakan internet tidak berfungsi.`,`Minta izin mengisi daya telepon.`,`Tanyakan lokasi membeli kartu SIM.`,`Buat dua kalimat dengan “nie działa”.`]},{day: 23, title: `Mengirim pesan dan membuat janji`, title_native: `Wiadomości i umawianie się`, focus: `Saat bertemu teman baru di Polandia, Anda mungkin perlu mengirim pesan, mengatur jam, dan mengonfirmasi lokasi. Hari ini melatih bahasa praktis untuk rencana sosial.`, vocab: [{pl: `wiadomość`, id: `pesan`, ipa: `vya-do-moshch`},{pl: `spotkanie`, id: `pertemuan`, ipa: `spot-ka-nye`},{pl: `czas`, id: `waktu`, ipa: `chas`},{pl: `miejsce`, id: `tempat`, ipa: `myeys-tse`},{pl: `numer`, id: `nomor`, ipa: `nu-mer`},{pl: `telefon`, id: `telepon`, ipa: `te-le-fon`},{pl: `później`, id: `nanti`, ipa: `puzh-nyey`},{pl: `teraz`, id: `sekarang`, ipa: `te-raz`},{pl: `czekam`, id: `saya menunggu`, ipa: `che-kam`},{pl: `pasuje`, id: `cocok / sesuai`, ipa: `pa-su-ye`}], phrases: [{pl: `Jaki masz numer telefonu?`, id: `Berapa nomor teleponmu?`, ipa: `ya-ki mash nu-mer te-le-fo-nu`},{pl: `Napiszę później.`, id: `Saya akan menulis nanti.`, ipa: `na-pi-she puzh-nyey`},{pl: `Gdzie się spotkamy?`, id: `Di mana kita bertemu?`, ipa: `gje shye spot-ka-mi`},{pl: `O której się spotkamy?`, id: `Jam berapa kita bertemu?`, ipa: `o ktu-rey shye spot-ka-mi`},{pl: `Pasuje mi.`, id: `Itu cocok untuk saya.`, ipa: `pa-su-ye mi`},{pl: `Czekam przed kawiarnią.`, id: `Saya menunggu di depan kafe.`, ipa: `che-kam pshet ka-vyar-nyom`}], grammar: `Kata “się” sering muncul dalam kata kerja refleksif atau frasa tetap, seperti “spotkamy się”. Untuk rencana, Anda tidak perlu memahami semua teori; hafalkan “Gdzie się spotkamy?” dan “O której się spotkamy?”. “Pasuje mi” sangat alami untuk menyetujui waktu atau tempat.`, practice: [`Tanyakan nomor telepon seseorang.`,`Katakan Anda akan menulis nanti.`,`Tanyakan tempat bertemu.`,`Tanyakan jam bertemu.`,`Katakan bahwa waktu atau tempat itu cocok untuk Anda.`]},{day: 24, title: `Di rumah tamu atau apartemen`, title_native: `W pensjonacie lub apartamencie`, focus: `Jika Anda menginap di apartemen sewaan di Kraków atau Gdańsk, Anda perlu memahami kunci, pintu, dapur, dan aturan rumah. Hari ini fokus pada kebutuhan menginap harian.`, vocab: [{pl: `apartament`, id: `apartemen`, ipa: `a-par-ta-ment`},{pl: `drzwi`, id: `pintu`, ipa: `dzhvi`},{pl: `klucz`, id: `kunci`, ipa: `klooch`},{pl: `kuchnia`, id: `dapur`, ipa: `kuh-nya`},{pl: `łazienka`, id: `kamar mandi`, ipa: `wa-zhyen-ka`},{pl: `prysznic`, id: `shower`, ipa: `pri-shnits`},{pl: `ręcznik`, id: `handuk`, ipa: `rench-nik`},{pl: `cisza`, id: `ketenangan`, ipa: `chi-sha`},{pl: `sąsiad`, id: `tetangga`, ipa: `son-shad`},{pl: `ogrzewanie`, id: `pemanas`, ipa: `o-gzhe-va-nye`}], phrases: [{pl: `Gdzie jest klucz?`, id: `Di mana kuncinya?`, ipa: `gje yest klooch`},{pl: `Drzwi są zamknięte.`, id: `Pintunya terkunci.`, ipa: `dzhvi som zamk-nye-te`},{pl: `Czy jest ręcznik?`, id: `Apakah ada handuk?`, ipa: `chi yest rench-nik`},{pl: `Ogrzewanie nie działa.`, id: `Pemanas tidak berfungsi.`, ipa: `o-gzhe-va-nye nye ja-wa`},{pl: `Gdzie jest łazienka?`, id: `Di mana kamar mandi?`, ipa: `gje yest wa-zhyen-ka`},{pl: `Proszę o ciszę.`, id: `Mohon tenang.`, ipa: `pro-she o chi-she`}], grammar: `“Są” berarti “adalah/ada” untuk bentuk jamak, seperti “Drzwi są zamknięte”. Menariknya, “drzwi” selalu berbentuk jamak dalam bahasa Polandia. Untuk masalah apartemen, gabungkan nama benda dengan “nie działa”.`, practice: [`Tanyakan lokasi kunci.`,`Katakan pintu terkunci.`,`Tanyakan apakah ada handuk.`,`Laporkan pemanas tidak berfungsi.`,`Tanyakan lokasi kamar mandi.`]},{day: 25, title: `Kantor pos dan pengiriman`, title_native: `Poczta i wysyłka`, focus: `Di kantor pos Polandia, Anda mungkin ingin mengirim kartu pos, paket, atau membeli perangko. Hari ini melatih bahasa pengiriman sederhana untuk wisatawan.`, vocab: [{pl: `poczta`, id: `kantor pos`, ipa: `poch-ta`},{pl: `kartka`, id: `kartu pos`, ipa: `kart-ka`},{pl: `list`, id: `surat`, ipa: `list`},{pl: `paczka`, id: `paket`, ipa: `pach-ka`},{pl: `znaczek`, id: `perangko`, ipa: `zna-chek`},{pl: `adres`, id: `alamat`, ipa: `a-dres`},{pl: `koperta`, id: `amplop`, ipa: `ko-per-ta`},{pl: `wysyłać`, id: `mengirim`, ipa: `vi-si-wach`},{pl: `odbiór`, id: `pengambilan`, ipa: `od-byur`},{pl: `priorytet`, id: `prioritas`, ipa: `pryo-ri-tet`}], phrases: [{pl: `Chcę wysłać kartkę.`, id: `Saya ingin mengirim kartu pos.`, ipa: `htse vi-swach kart-ke`},{pl: `Poproszę znaczek.`, id: `Saya minta perangko.`, ipa: `po-pro-she zna-chek`},{pl: `Ile kosztuje wysyłka?`, id: `Berapa biaya pengiriman?`, ipa: `i-le kosh-too-ye vi-siw-ka`},{pl: `To jest adres.`, id: `Ini alamatnya.`, ipa: `to yest a-dres`},{pl: `Do Indonezji, proszę.`, id: `Ke Indonesia, tolong.`, ipa: `do in-do-nez-yi, pro-she`},{pl: `Czy mogę wysłać paczkę?`, id: `Bisakah saya mengirim paket?`, ipa: `chi mo-ge vi-swach pach-ke`}], grammar: `“Chcę” berarti “saya ingin” dan diikuti kata kerja bentuk dasar, seperti “wysłać”. Untuk tujuan negara, gunakan “do”: “do Indonezji”. Di kantor pos, frasa pendek dan dokumen tertulis seperti alamat sangat membantu.`, practice: [`Katakan Anda ingin mengirim kartu pos.`,`Minta perangko.`,`Tanyakan biaya pengiriman.`,`Katakan paket atau kartu dikirim ke Indonesia.`,`Tunjukkan alamat dengan “To jest adres”.`]},{day: 26, title: `Batasan, preferensi, dan kebutuhan`, title_native: `Ograniczenia, preferencje i potrzeby`, focus: `Saat makan, belanja, atau bepergian, Anda perlu menjelaskan apa yang Anda suka, tidak suka, bisa, atau tidak bisa. Hari ini membuat bahasa Anda lebih personal dan praktis.`, vocab: [{pl: `lubię`, id: `saya suka`, ipa: `lu-bye`},{pl: `nie lubię`, id: `saya tidak suka`, ipa: `nye lu-bye`},{pl: `chcę`, id: `saya ingin`, ipa: `htse`},{pl: `nie chcę`, id: `saya tidak ingin`, ipa: `nye htse`},{pl: `mogę`, id: `saya bisa / boleh`, ipa: `mo-ge`},{pl: `nie mogę`, id: `saya tidak bisa`, ipa: `nye mo-ge`},{pl: `potrzebuję`, id: `saya butuh`, ipa: `po-tshe-boo-ye`},{pl: `wolę`, id: `saya lebih suka`, ipa: `vo-le`},{pl: `bez`, id: `tanpa`, ipa: `bez`},{pl: `z`, id: `dengan`, ipa: `z`}], phrases: [{pl: `Lubię kawę.`, id: `Saya suka kopi.`, ipa: `lu-bye ka-ve`},{pl: `Nie lubię mięsa.`, id: `Saya tidak suka daging.`, ipa: `nye lu-bye myen-sa`},{pl: `Chcę coś lekkiego.`, id: `Saya ingin sesuatu yang ringan.`, ipa: `htse tsosh lek-kye-go`},{pl: `Nie mogę jeść orzechów.`, id: `Saya tidak bisa makan kacang.`, ipa: `nye mo-ge yeshch o-zhe-huf`},{pl: `Wolę wodę.`, id: `Saya lebih suka air.`, ipa: `vo-le vo-de`},{pl: `Potrzebuję pomocy.`, id: `Saya butuh bantuan.`, ipa: `po-tshe-boo-ye po-mo-tsi`}], grammar: `Kata kerja “lubię”, “chcę”, “mogę”, dan “potrzebuję” sangat kuat untuk kebutuhan perjalanan. Setelah beberapa kata ini, bentuk kata benda bisa berubah, tetapi jangan takut berbicara. Pesan Anda tetap dapat dipahami jika memakai pola dasar dengan jelas.`, practice: [`Katakan tiga hal yang Anda suka.`,`Katakan satu hal yang tidak Anda suka.`,`Katakan Anda ingin sesuatu yang ringan.`,`Jelaskan satu makanan yang tidak bisa Anda makan.`,`Buat kalimat dengan “wolę”.`]},{day: 27, title: `Percakapan di kereta antarkota`, title_native: `Rozmowa w pociągu międzymiastowym`, focus: `Dalam perjalanan dari Warszawa ke Kraków, Anda mungkin berbicara dengan kondektur atau penumpang lain. Hari ini melatih kursi, tiket, bagasi, dan percakapan sopan di kereta.`, vocab: [{pl: `pociąg`, id: `kereta`, ipa: `po-chong`},{pl: `wagon`, id: `gerbong`, ipa: `va-gon`},{pl: `miejsce`, id: `tempat duduk`, ipa: `myeys-tse`},{pl: `bagaż`, id: `bagasi`, ipa: `ba-gash`},{pl: `konduktor`, id: `kondektur`, ipa: `kon-duk-tor`},{pl: `opóźnienie`, id: `keterlambatan`, ipa: `o-puzh-nye-nye`},{pl: `stacja`, id: `stasiun`, ipa: `sta-tsya`},{pl: `przedział`, id: `kompartemen`, ipa: `pshe-jaw`},{pl: `cisza`, id: `tenang`, ipa: `chi-sha`},{pl: `rezerwacja`, id: `reservasi`, ipa: `re-zer-va-tsya`}], phrases: [{pl: `To moje miejsce.`, id: `Ini tempat duduk saya.`, ipa: `to mo-ye myeys-tse`},{pl: `Czy to jest wagon drugi?`, id: `Apakah ini gerbong dua?`, ipa: `chi to yest va-gon dru-gi`},{pl: `Mam bilet elektroniczny.`, id: `Saya punya tiket elektronik.`, ipa: `mam bi-let e-lek-tro-nich-ni`},{pl: `Gdzie mogę położyć bagaż?`, id: `Di mana saya bisa meletakkan bagasi?`, ipa: `gje mo-ge po-wo-zhich ba-gash`},{pl: `Czy pociąg ma opóźnienie?`, id: `Apakah kereta terlambat?`, ipa: `chi po-chong ma o-puzh-nye-nye`},{pl: `Kiedy będziemy w Krakowie?`, id: `Kapan kita akan tiba di Kraków?`, ipa: `kye-di ben-je-mi f kra-ko-vye`}], grammar: `“Moje” dipakai untuk kata benda netral seperti “miejsce”. Di kereta, nomor gerbong disebut “wagon pierwszy”, “wagon drugi”, dan seterusnya. Untuk tiket digital, “Mam bilet elektroniczny” cukup jelas saat kondektur memeriksa tiket.`, practice: [`Katakan bahwa ini tempat duduk Anda.`,`Tanyakan apakah ini gerbong kedua.`,`Katakan Anda punya tiket elektronik.`,`Tanyakan tempat meletakkan bagasi.`,`Tanyakan apakah kereta terlambat.`]},{day: 28, title: `Menjelaskan masalah dan meminta solusi`, title_native: `Wyjaśnianie problemów i proszenie o rozwiązanie`, focus: `Tidak semua perjalanan berjalan mulus: kamar bisa bermasalah, tiket salah, atau barang hilang. Hari ini membantu Anda menjelaskan masalah dengan tenang dan meminta solusi.`, vocab: [{pl: `problem`, id: `masalah`, ipa: `pro-blem`},{pl: `błąd`, id: `kesalahan`, ipa: `bwond`},{pl: `zgubiony`, id: `hilang`, ipa: `zgu-byo-ni`},{pl: `zepsuty`, id: `rusak`, ipa: `zep-su-ti`},{pl: `brudny`, id: `kotor`, ipa: `brud-ni`},{pl: `głośno`, id: `berisik`, ipa: `gwosh-no`},{pl: `rachunek`, id: `tagihan`, ipa: `ra-hu-nek`},{pl: `rezerwacja`, id: `reservasi`, ipa: `re-zer-va-tsya`},{pl: `zmiana`, id: `perubahan`, ipa: `zmya-na`},{pl: `rozwiązanie`, id: `solusi`, ipa: `roz-vyon-za-nye`}], phrases: [{pl: `Mam problem.`, id: `Saya punya masalah.`, ipa: `mam pro-blem`},{pl: `To jest błąd.`, id: `Ini kesalahan.`, ipa: `to yest bwond`},{pl: `Pokój jest brudny.`, id: `Kamarnya kotor.`, ipa: `po-kuy yest brud-ni`},{pl: `Klucz nie działa.`, id: `Kunci tidak berfungsi.`, ipa: `klooch nye ja-wa`},{pl: `Chcę zmienić rezerwację.`, id: `Saya ingin mengubah reservasi.`, ipa: `htse zmye-nich re-zer-va-tsye`},{pl: `Czy można to naprawić?`, id: `Apakah ini bisa diperbaiki?`, ipa: `chi mozh-na to na-pra-vich`}], grammar: `Untuk menjelaskan masalah, kalimat pendek lebih baik: “Mam problem”, lalu benda + “nie działa” atau “jest brudny”. “Czy można...?” membantu meminta solusi tanpa terdengar terlalu menuntut. Di Polandia, nada tenang dan langsung biasanya efektif.`, practice: [`Katakan “Mam problem” dengan nada sopan.`,`Jelaskan bahwa kunci tidak berfungsi.`,`Jelaskan bahwa kamar kotor.`,`Katakan Anda ingin mengubah reservasi.`,`Tanyakan apakah sesuatu bisa diperbaiki.`]},{day: 29, title: `Membicarakan pengalaman perjalanan`, title_native: `Opowiadanie o podróży`, focus: `Setelah beberapa hari di Polandia, Anda bisa menceritakan apa yang Anda lihat, makan, dan sukai. Hari ini membangun kalimat sederhana tentang pengalaman perjalanan.`, vocab: [{pl: `podróż`, id: `perjalanan`, ipa: `po-droosh`},{pl: `widziałem`, id: `saya melihat`, ipa: `vi-jaw-em`},{pl: `widziałam`, id: `saya melihat`, ipa: `vi-ja-wam`},{pl: `jadłem`, id: `saya makan`, ipa: `yad-wem`},{pl: `jadłam`, id: `saya makan`, ipa: `yad-wam`},{pl: `byłem`, id: `saya pernah/berada`, ipa: `bi-wem`},{pl: `byłam`, id: `saya pernah/berada`, ipa: `bi-wam`},{pl: `piękny`, id: `indah`, ipa: `pyenk-ni`},{pl: `ciekawy`, id: `menarik`, ipa: `che-ka-vi`},{pl: `najlepszy`, id: `terbaik`, ipa: `nay-lep-shi`}], phrases: [{pl: `Byłem w Krakowie.`, id: `Saya berada di Kraków.`, ipa: `bi-wem f kra-ko-vye`},{pl: `Byłam w Krakowie.`, id: `Saya berada di Kraków.`, ipa: `bi-wam f kra-ko-vye`},{pl: `Widziałem zamek.`, id: `Saya melihat kastel.`, ipa: `vi-jaw-em za-mek`},{pl: `Widziałam zamek.`, id: `Saya melihat kastel.`, ipa: `vi-ja-wam za-mek`},{pl: `Jadłem pierogi.`, id: `Saya makan pierogi.`, ipa: `yad-wem pye-ro-gi`},{pl: `To była najlepsza podróż.`, id: `Itu perjalanan terbaik.`, ipa: `to bi-wa nay-lep-sha po-droosh`}], grammar: `Bentuk lampau bahasa Polandia sering berubah menurut gender pembicara: laki-laki “byłem, widziałem, jadłem”, perempuan “byłam, widziałam, jadłam”. Ini penting ketika menceritakan pengalaman. Anda bisa memilih bentuk yang cocok untuk diri Anda dan menghafalnya sebagai paket.`, practice: [`Ceritakan kota yang pernah Anda kunjungi dengan “Byłem/Byłam w...”.`,`Katakan Anda melihat kastel.`,`Katakan Anda makan pierogi.`,`Gunakan kata “piękny” untuk memuji tempat.`,`Buat tiga kalimat pengalaman perjalanan.`]},{day: 30, title: `Hari perjalanan lengkap`, title_native: `Pełny dzień podróży`, focus: `Hari terakhir menggabungkan semua keterampilan: menyapa, bertanya arah, memesan, membayar, dan berbicara ringan. Bayangkan satu hari penuh di Kraków, dari hotel ke kafe, museum, restoran, lalu kembali dengan tram.`, vocab: [{pl: `dzień`, id: `hari`, ipa: `djen`},{pl: `plan`, id: `rencana`, ipa: `plan`},{pl: `rano`, id: `pagi`, ipa: `ra-no`},{pl: `po południu`, id: `sore / setelah siang`, ipa: `po po-wud-nyu`},{pl: `wieczorem`, id: `malam hari`, ipa: `vye-cho-rem`},{pl: `razem`, id: `bersama`, ipa: `ra-zem`},{pl: `sam`, id: `sendiri laki-laki`, ipa: `sam`},{pl: `sama`, id: `sendiri perempuan`, ipa: `sa-ma`},{pl: `wracam`, id: `saya kembali`, ipa: `vra-tsam`},{pl: `gotowy`, id: `siap`, ipa: `go-to-vi`}], phrases: [{pl: `Mam plan na dzisiaj.`, id: `Saya punya rencana untuk hari ini.`, ipa: `mam plan na ji-shay`},{pl: `Rano idę do kawiarni.`, id: `Pagi hari saya pergi ke kafe.`, ipa: `ra-no i-de do ka-vyar-ni`},{pl: `Po południu zwiedzam muzeum.`, id: `Sore hari saya mengunjungi museum.`, ipa: `po po-wud-nyu zvye-jam mu-ze-um`},{pl: `Wieczorem jem kolację.`, id: `Malam hari saya makan malam.`, ipa: `vye-cho-rem yem ko-la-tsye`},{pl: `Wracam do hotelu tramwajem.`, id: `Saya kembali ke hotel dengan trem.`, ipa: `vra-tsam do ho-te-lu tram-va-yem`},{pl: `Jestem gotowy.`, id: `Saya siap.`, ipa: `yes-tem go-to-vi`}], grammar: `Hari ini Anda menggabungkan pola waktu: “rano”, “po południu”, dan “wieczorem”. Kata kerja seperti “idę”, “jem”, dan “wracam” sudah cukup untuk membuat cerita perjalanan sederhana. Tujuan utama bukan kesempurnaan, tetapi kemampuan menyelesaikan kebutuhan nyata dengan sopan.`, practice: [`Buat rencana hari ini dengan tiga waktu: pagi, sore, malam.`,`Pesan sesuatu di kafe dengan “Poproszę...”.`,`Tanyakan arah ke museum.`,`Minta tagihan dan pilih pembayaran kartu.`,`Ceritakan hari Anda dalam lima kalimat bahasa Polandia sederhana.`]}];

var CONVERSATIONS_ID_PL = [{id: 1, title: `Memesan kopi di kafe`, scene: `Anda berada di kafe kecil dekat Rynek Główny di Kraków. Barista menyapa Anda lebih dulu, dan Anda ingin memesan kopi tanpa gula serta kue kecil.`, lines: [{who: `them`, pl: `Dzień dobry, co podać?`, id: `Selamat siang, mau pesan apa?`},{who: `you`, pl: `Dzień dobry, poproszę kawę.`, id: `Selamat siang, saya minta kopi.`},{who: `them`, pl: `Mała czy duża?`, id: `Kecil atau besar?`},{who: `you`, pl: `Duża, proszę.`, id: `Besar, tolong.`},{who: `them`, pl: `Z mlekiem?`, id: `Dengan susu?`},{who: `you`, pl: `Tak, z mlekiem, ale bez cukru.`, id: `Ya, dengan susu, tetapi tanpa gula.`},{who: `them`, pl: `Coś jeszcze?`, id: `Ada lagi?`},{who: `you`, pl: `Tak, poproszę ciastko.`, id: `Ya, saya minta kue kecil.`},{who: `them`, pl: `Na miejscu czy na wynos?`, id: `Di sini atau dibawa pergi?`},{who: `you`, pl: `Na miejscu, proszę.`, id: `Di sini, tolong.`},{who: `them`, pl: `To będzie osiemnaście złotych.`, id: `Totalnya delapan belas złoty.`},{who: `you`, pl: `Kartą, proszę.`, id: `Dengan kartu, tolong.`}]},{id: 2, title: `Check-in di hotel`, scene: `Anda tiba di hotel di Warszawa setelah perjalanan panjang. Resepsionis meminta nama dan paspor Anda, lalu menjelaskan sarapan dan check-out.`, lines: [{who: `them`, pl: `Dzień dobry, witamy w hotelu.`, id: `Selamat siang, selamat datang di hotel.`},{who: `you`, pl: `Dzień dobry, mam rezerwację.`, id: `Selamat siang, saya punya reservasi.`},{who: `them`, pl: `Na jakie nazwisko?`, id: `Atas nama siapa?`},{who: `you`, pl: `Na nazwisko Cannon.`, id: `Atas nama Cannon.`},{who: `them`, pl: `Poproszę paszport.`, id: `Tolong paspornya.`},{who: `you`, pl: `Proszę bardzo.`, id: `Silakan.`},{who: `them`, pl: `Pański pokój jest na drugim piętrze.`, id: `Kamar Anda ada di lantai dua.`},{who: `you`, pl: `Dziękuję, czy śniadanie jest w cenie?`, id: `Terima kasih, apakah sarapan termasuk harga?`},{who: `them`, pl: `Tak, śniadanie jest od siódmej do dziesiątej.`, id: `Ya, sarapan dari jam tujuh sampai sepuluh.`},{who: `you`, pl: `O której jest wymeldowanie?`, id: `Check-out jam berapa?`},{who: `them`, pl: `Wymeldowanie jest o jedenastej.`, id: `Check-out jam sebelas.`},{who: `you`, pl: `Dziękuję bardzo.`, id: `Terima kasih banyak.`}]},{id: 3, title: `Bertanya arah ke alun-alun`, scene: `Anda berjalan di pusat Wrocław dan ingin menuju alun-alun utama. Anda menghentikan seseorang dengan sopan dan meminta arah yang sederhana.`, lines: [{who: `you`, pl: `Przepraszam, gdzie jest rynek?`, id: `Permisi, di mana alun-alun utama?`},{who: `them`, pl: `Rynek jest blisko.`, id: `Alun-alun dekat.`},{who: `you`, pl: `Czy mam iść prosto?`, id: `Apakah saya harus jalan lurus?`},{who: `them`, pl: `Tak, proszę iść prosto.`, id: `Ya, silakan jalan lurus.`},{who: `you`, pl: `Potem w lewo czy w prawo?`, id: `Lalu ke kiri atau ke kanan?`},{who: `them`, pl: `Potem w prawo, przy kościele.`, id: `Lalu ke kanan, dekat gereja.`},{who: `you`, pl: `To jest daleko?`, id: `Apakah itu jauh?`},{who: `them`, pl: `Nie, pięć minut pieszo.`, id: `Tidak, lima menit jalan kaki.`},{who: `you`, pl: `Dziękuję, mówię tylko trochę po polsku.`, id: `Terima kasih, saya hanya berbicara sedikit bahasa Polandia.`},{who: `them`, pl: `Bardzo dobrze!`, id: `Sangat bagus!`},{who: `you`, pl: `Miłego dnia.`, id: `Semoga harimu menyenangkan.`},{who: `them`, pl: `Nawzajem.`, id: `Sama-sama / Anda juga.`}]},{id: 4, title: `Makan malam di restoran`, scene: `Anda masuk ke restoran di Gdańsk untuk makan malam. Pelayan menawarkan meja, menu, dan rekomendasi makanan khas Polandia.`, lines: [{who: `them`, pl: `Dobry wieczór, stolik dla ilu osób?`, id: `Selamat malam, meja untuk berapa orang?`},{who: `you`, pl: `Stolik dla dwóch osób, proszę.`, id: `Meja untuk dua orang, tolong.`},{who: `them`, pl: `Proszę za mną.`, id: `Silakan ikut saya.`},{who: `you`, pl: `Dziękuję, poproszę menu.`, id: `Terima kasih, saya minta menu.`},{who: `them`, pl: `Oczywiście, dziś polecam pierogi.`, id: `Tentu, hari ini saya rekomendasikan pierogi.`},{who: `you`, pl: `Czy pierogi są z mięsem?`, id: `Apakah pierogi dengan daging?`},{who: `them`, pl: `Mamy pierogi z mięsem i z serem.`, id: `Kami punya pierogi dengan daging dan dengan keju.`},{who: `you`, pl: `Poproszę pierogi z serem.`, id: `Saya minta pierogi dengan keju.`},{who: `them`, pl: `Co do picia?`, id: `Minumnya apa?`},{who: `you`, pl: `Wodę, proszę.`, id: `Air, tolong.`},{who: `them`, pl: `Czy coś jeszcze?`, id: `Ada lagi?`},{who: `you`, pl: `Nie, to wszystko, dziękuję.`, id: `Tidak, itu saja, terima kasih.`}]},{id: 5, title: `Membeli tiket transportasi`, scene: `Anda berada di mesin tiket, tetapi bingung memilih tiket yang benar. Anda bertanya kepada petugas di stasiun metro Warszawa.`, lines: [{who: `them`, pl: `Dzień dobry, w czym mogę pomóc?`, id: `Selamat siang, apa yang bisa saya bantu?`},{who: `you`, pl: `Dzień dobry, potrzebuję biletu do centrum.`, id: `Selamat siang, saya butuh tiket ke pusat kota.`},{who: `them`, pl: `Normalny czy ulgowy?`, id: `Reguler atau diskon?`},{who: `you`, pl: `Normalny, proszę.`, id: `Reguler, tolong.`},{who: `them`, pl: `Jeden bilet?`, id: `Satu tiket?`},{who: `you`, pl: `Tak, jeden bilet.`, id: `Ya, satu tiket.`},{who: `them`, pl: `Proszę kupić tutaj, w biletomacie.`, id: `Silakan beli di sini, di mesin tiket.`},{who: `you`, pl: `Czy mogę zapłacić kartą?`, id: `Apakah saya bisa membayar dengan kartu?`},{who: `them`, pl: `Tak, kartą albo gotówką.`, id: `Ya, dengan kartu atau tunai.`},{who: `you`, pl: `Czy ten bilet jest ważny w metrze?`, id: `Apakah tiket ini valid di metro?`},{who: `them`, pl: `Tak, w metrze, tramwaju i autobusie.`, id: `Ya, di metro, trem, dan bus.`},{who: `you`, pl: `Dziękuję za pomoc.`, id: `Terima kasih atas bantuannya.`}]},{id: 6, title: `Berbelanja jaket`, scene: `Anda berada di toko pakaian di Zakopane karena cuaca lebih dingin dari perkiraan. Anda ingin mencoba jaket dan mencari ukuran yang lebih besar.`, lines: [{who: `them`, pl: `Dzień dobry, mogę pomóc?`, id: `Selamat siang, bisa saya bantu?`},{who: `you`, pl: `Dzień dobry, szukam kurtki.`, id: `Selamat siang, saya mencari jaket.`},{who: `them`, pl: `Jaki rozmiar?`, id: `Ukuran apa?`},{who: `you`, pl: `Nie wiem, czy mogę przymierzyć?`, id: `Saya tidak tahu, bolehkah saya mencoba?`},{who: `them`, pl: `Oczywiście, przymierzalnia jest tam.`, id: `Tentu, kamar pas ada di sana.`},{who: `you`, pl: `Dziękuję, ta kurtka jest za mała.`, id: `Terima kasih, jaket ini terlalu kecil.`},{who: `them`, pl: `Mamy większy rozmiar.`, id: `Kami punya ukuran lebih besar.`},{who: `you`, pl: `Świetnie, poproszę większy rozmiar.`, id: `Bagus, saya minta ukuran lebih besar.`},{who: `them`, pl: `Jak pasuje?`, id: `Bagaimana, cocok?`},{who: `you`, pl: `Pasuje dobrze, wezmę to.`, id: `Cocok dengan baik, saya ambil ini.`},{who: `them`, pl: `Płatność kartą czy gotówką?`, id: `Pembayaran dengan kartu atau tunai?`},{who: `you`, pl: `Kartą, proszę.`, id: `Dengan kartu, tolong.`}]},{id: 7, title: `Di apotek`, scene: `Anda masuk ke apotek di Poznań karena kepala Anda sakit dan Anda merasa sedikit demam. Apoteker menanyakan gejala dan apakah Anda punya alergi.`, lines: [{who: `them`, pl: `Dzień dobry, słucham.`, id: `Selamat siang, silakan.`},{who: `you`, pl: `Dzień dobry, boli mnie głowa.`, id: `Selamat siang, kepala saya sakit.`},{who: `them`, pl: `Czy ma pan gorączkę?`, id: `Apakah Bapak demam?`},{who: `you`, pl: `Tak, mam trochę gorączkę.`, id: `Ya, saya sedikit demam.`},{who: `them`, pl: `Czy ma pan alergię?`, id: `Apakah Bapak punya alergi?`},{who: `you`, pl: `Nie, nie mam alergii.`, id: `Tidak, saya tidak punya alergi.`},{who: `them`, pl: `Proszę ten lek i dużo wody.`, id: `Silakan obat ini dan banyak air.`},{who: `you`, pl: `Czy potrzebuję recepty?`, id: `Apakah saya perlu resep?`},{who: `them`, pl: `Nie, recepta nie jest potrzebna.`, id: `Tidak, resep tidak diperlukan.`},{who: `you`, pl: `Ile to kosztuje?`, id: `Berapa harganya?`},{who: `them`, pl: `Dwadzieścia złotych.`, id: `Dua puluh złoty.`},{who: `you`, pl: `Dziękuję, kartą proszę.`, id: `Terima kasih, dengan kartu tolong.`}]},{id: 8, title: `Obrolan ringan dengan orang lokal`, scene: `Anda duduk di bangku taman di Kraków dan seseorang mulai berbicara tentang cuaca. Anda memakai bahasa Polandia sederhana untuk berbincang ramah.`, lines: [{who: `you`, pl: `Dzień dobry, ładna pogoda dzisiaj.`, id: `Selamat siang, cuaca bagus hari ini.`},{who: `them`, pl: `Tak, bardzo ładna.`, id: `Ya, sangat bagus.`},{who: `you`, pl: `Jestem tu pierwszy raz.`, id: `Saya di sini untuk pertama kali.`},{who: `them`, pl: `Naprawdę? Jak się podoba Kraków?`, id: `Benarkah? Bagaimana menurut Anda Kraków?`},{who: `you`, pl: `Bardzo mi się podoba. To piękne miasto.`, id: `Saya sangat menyukainya. Ini kota yang indah.`},{who: `them`, pl: `Skąd jesteś?`, id: `Kamu dari mana?`},{who: `you`, pl: `Jestem z Indonezji.`, id: `Saya dari Indonesia.`},{who: `them`, pl: `Mówisz po polsku?`, id: `Kamu berbicara bahasa Polandia?`},{who: `you`, pl: `Mówię trochę po polsku.`, id: `Saya berbicara sedikit bahasa Polandia.`},{who: `them`, pl: `Bardzo dobrze.`, id: `Sangat bagus.`},{who: `you`, pl: `Dziękuję, ludzie tutaj są mili.`, id: `Terima kasih, orang-orang di sini baik.`},{who: `them`, pl: `Miło to słyszeć.`, id: `Senang mendengarnya.`}]}];